def process(list, index):
    if list is None:
        return []
    result = list.copy() if hasattr(list, 'copy') else list[:]
    try:
        idx = int(index) if index is not None else 0
        if 0 <= idx < len(result):
            result.pop(idx)
    except (IndexError, TypeError, ValueError):
        pass
    return result
